prompt.gate_pipeline_spec:
```typescript
// GatePipeline.tsx 组件结构

const GATES = [
  { id: 1, name: 'Agency Gate',     metric: 'premise_rewrite_rate' },
  { id: 2, name: 'Excursion Gate',  metric: 'effective_exploration_evidence' },
  { id: 3, name: 'Learning Gate',   metric: 'no_assist_trajectory' },
  { id: 4, name: 'Relational Gate', metric: 'compliance_signal_score' },
  { id: 5, name: 'Causal Gate',     metric: 'causal_diagnostics_triple' },
  { id: 6, name: 'Audit Gate',      metric: 'audit_health' },
  { id: 7, name: 'Framing Gate',    metric: 'independent_framing_audit_pass' },
  { id: 8, name: 'Window Gate',     metric: 'window_schema_version_consistency' },
];

type GateStatus = 'pass' | 'warn' | 'block';

// 每行: ●PASS(鼠尾草绿) / ⚠WARN(珊瑚糖) / ●BLOCK(柔和红) | 名称 | 指标值
// 展开: 历史趋势迷你图 | 裁决依据 | 最近事件
// 左上角固定: 整体状态(● ALL PASS | ⚠ WARN | ● BLOCKED)

interface GateState {
  id: number;
  name: string;
  status: GateStatus;
  metric: string;
  value: number;
  detail?: {
    trend: 'up' | 'down' | 'stable';
    last_event: string;
    threshold: number;
  };
}
```

| 状态 | 颜色 | 含义 |
|------|------|------|
| PASS | #9CB59B | 门禁通过 |
| WARN | #FEDDD8 | 指标接近阈值 |
| BLOCK | #FF8A80 | 指标超阈值 |

