// 不出现任何技术术语
// 不使用: gate / pipeline / audit / block / P0 / P1 / 门禁 / 阻断
```

prompt.use_auth_spec:
```typescript
// useAuth.ts — RBAC 权限管理

type Role = 'user' | 'admin' | 'debug';

interface AuthState {
  role: Role;
  token: string | null;
}

function useAuth() {
  const [auth, setAuth] = useState(() => {
    const stored = sessionStorage.getItem('coach_auth');
    return stored ? JSON.parse(stored) : { role: 'user', token: null };
  });

  const canView = (requiredRole: Role): boolean => {
    const roleHierarchy = { user: 0, admin: 1, debug: 2 };
    return roleHierarchy[auth.role] >= roleHierarchy[requiredRole];
  };

  const setRole = (role: Role, token: string) => {
    const newAuth = { role, token };
    sessionStorage.setItem('coach_auth', JSON.stringify(newAuth));
    setAuth(newAuth);
  };

  return { auth, canView, setRole };
}
```
